                "dns": {
                    "status": "COMPLIANT"
                },
                "syslog": {
                    "status": "NON_COMPLIANT",
                    "current": {
                        "servers": [
                            {
                                "hostname": "8.8.4.4",
                                "protocol": "TLS",
                                "port": 90
                            }
                        ]
                    },
                    "desired": {
                        "servers": [
                            {
                                "hostname": "8.8.4.4",
                                "port": 90,
                                "protocol": "TLS"
                            },
                            {
                                "hostname": "8.8.1.8",
                                "port": 90,
                                "protocol": "TLS"
                            }
                        ]
                    }
                }
            }
        }
    },
    "status": "NON_COMPLIANT"
}
```

Sample response for compliant case:

```json
{
    "changes": {
        "compliance_config": {
            "vcenter": {
                "ntp": {
                    "status": "COMPLIANT"
